## Template Email

Génération de messages formatés avec templates Go natifs (inspiré du composant Velocity d'Apache Camel).

```go title="template_email.go"
package main

import (
    "github.com/tranchida/gocamel"
)

// templates/email.tmpl:
// Bonjour {{.Headers.name}},
// 
// {{.Body}}
//
// Envoyé le {{now | formatDate "2006-01-02"}}

func main() {
    ctx := gocamel.NewCamelContext()
    ctx.AddComponent("template", gocamel.NewTemplateComponent())

    route := ctx.CreateRouteBuilder().
        From("direct:notify").
        SetHeader("name", "Alice").
        SetBody("Votre commande est prête !").
        To("template:templates/email.tmpl").
        Log("Email généré: ${body}").
        Build()

    ctx.AddRoute(route)
    ctx.Start()
    select {}
}
</code></pre>

Fonction Description Exemple <code>upper</code> Majuscules <code>{{.Body | upper}}</code> <code>lower</code> Minuscules <code>{{.Body | lower}}</code> <code>trim</code> Supprime espaces <code>{{.Body | trim}}</code> <code>now</code> Date actuelle <code>{{now}}</code> <code>formatDate</code> Formate date <code>{{now | formatDate "2006-01-02"}}</code> <code>toString</code> Convertit en string <code>{{.Body | toString}}</code> <code>safeHTML</code> HTML non échappé <code>{{.Body | safeHTML}}</code> <pre><code>## Split &amp; Aggregate

```go title="split_aggregate.go"
package main

import (
    "strings"
    "github.com/tranchida/gocamel"
)

type StringConcatStrategy struct{}

func (s *StringConcatStrategy) Aggregate(
    oldExchange, 
    newExchange *gocamel.Exchange,
) *gocamel.Exchange {
    if oldExchange == nil {
        return newExchange
    }
    oldBody := oldExchange.GetOut().GetBody().(string)
    newBody := newExchange.GetOut().GetBody().(string)
    oldExchange.GetOut().SetBody(oldBody + newBody)
    return oldExchange
}

func main() {
    ctx := gocamel.NewCamelContext()

    strategy := &amp;StringConcatStrategy{}
    repo := gocamel.NewMemoryAggregationRepository()

    route := ctx.CreateRouteBuilder().
        From("direct:start").
        Split(func(e *gocamel.Exchange) (any, error) {
            body := e.GetIn().GetBody().(string)
            return strings.Split(body, ","), nil
        }).
        To("direct:transform").
        End().
        Aggregate(gocamel.NewAggregator(
            func(e *gocamel.Exchange) string { return "group" },
            strategy, 
            repo,
        ).SetCompletionSize(3)).
        Build()

    ctx.AddRoute(route)
    ctx.Start()
    select {}
}
</code></pre>
